        private GameObject CreateObject(string name, PrimitiveType type)
        {
            var obj = GameObject.CreatePrimitive(type);
            obj.name = name;
            obj.transform.SetParent(transform);
            sceneObjects[name] = obj;
            return obj;
        }

        private void ApplyMaterial(GameObject obj, string colorHex, float roughness, float metallic)
        {
            var renderer = obj.GetComponent<Renderer>();
            var mat = new Material(Shader.Find("Standard"));
            mat.color = HexToColor(colorHex);
            mat.SetFloat("_Glossiness", 1f - roughness);
            mat.SetFloat("_Metallic", metallic);
            renderer.material = mat;
        }

        private void ApplyMetallicMaterial(GameObject obj, string colorHex, float metallic, float roughness)
        {
            ApplyMaterial(obj, colorHex, roughness, metallic);
        }

        private void ApplyEmissiveMaterial(GameObject obj, string colorHex, string emissiveHex, float emissiveIntensity, float opacity)
        {
            var renderer = obj.GetComponent<Renderer>();
            var mat = new Material(Shader.Find("Standard"));
            mat.color = HexToColor(colorHex);
            mat.SetColor("_EmissionColor", HexToColor(emissiveHex) * emissiveIntensity);
            mat.EnableKeyword("_EMISSION");

            if (opacity < 1.0f)
            {
                mat.SetFloat("_Mode", 3); // Transparent
                mat.SetInt("_SrcBlend", (int)UnityEngine.Rendering.BlendMode.SrcAlpha);
                mat.SetInt("_DstBlend", (int)UnityEngine.Rendering.BlendMode.OneMinusSrcAlpha);
                mat.SetInt("_ZWrite", 0);
                mat.DisableKeyword("_ALPHATEST_ON");
                mat.EnableKeyword("_ALPHABLEND_ON");
                mat.DisableKeyword("_ALPHAPREMULTIPLY_ON");
                mat.renderQueue = 3000;

                var color = mat.color;
                color.a = opacity;
                mat.color = color;
            }

            renderer.material = mat;
        }

        private void AddTraits(GameObject obj, string[] traits)
        {
            foreach (var trait in traits)
            {
                switch (trait)
                {
                    case "spatial":
                        obj.AddComponent<SpatialTrait>();
                        break;
                    case "networked":
                        obj.AddComponent<NetworkedTrait>();
                        break;
                    case "collision":
                        // Handled by MeshCollider
                        break;
                    case "emissive":
                        obj.AddComponent<EmissiveTrait>();
                        break;
                    case "grabbable":
                        obj.AddComponent<GrabbableTrait>();
                        break;
                    case "interactive":
                        obj.AddComponent<InteractiveTrait>();
                        break;
                    case "sittable":
                        obj.AddComponent<SittableTrait>();
                        break;
                }
            }
        }

        private HoloNPC CreateNPC(string name, Vector3 position, string dialogueId)
        {
            var npcObj = new GameObject(name);
            npcObj.transform.SetParent(transform);
            npcObj.transform.position = position;

            var npc = npcObj.AddComponent<HoloNPC>();
            npc.Initialize("humanoid", "idle", dialogueId);

            AddTraits(npcObj, new[] { "spatial", "networked", "dialogue" });

            return npc;
        }

        private HoloPortal CreatePortal(string name, Vector3 position, string destination, string label)
        {
            var portalObj = new GameObject(name);
            portalObj.transform.SetParent(transform);
            portalObj.transform.position = position;

            var portal = portalObj.AddComponent<HoloPortal>();
            portal.Initialize(destination, label, "swirl");

            AddTraits(portalObj, new[] { "spatial", "networked", "interactive" });

