            light.range = 10f;
        }

        private void CreateSpotLight(string name, Vector3 position, string colorHex, float intensity)
        {
            var lightObj = new GameObject(name);
            lightObj.transform.SetParent(transform);
            lightObj.transform.position = position;

            var light = lightObj.AddComponent<Light>();
            light.type = LightType.Spot;
            light.color = HexToColor(colorHex);
            light.intensity = intensity;
            light.range = 15f;
            light.spotAngle = 60f;
        }

        private void CreateAudioSource(string name, string clipName, bool loop, float volume, bool spatial, Vector3? position = null)
        {
            var audioObj = new GameObject(name);
            audioObj.transform.SetParent(transform);
            if (position.HasValue)
                audioObj.transform.position = position.Value;

            var audioSource = audioObj.AddComponent<AudioSource>();
            audioSource.clip = Resources.Load<AudioClip>($"Audio/{clipName}");
            audioSource.loop = loop;
            audioSource.volume = volume;
            audioSource.spatialBlend = spatial ? 1f : 0f;
            audioSource.playOnAwake = true;

            if (spatial)
            {
                audioSource.rolloffMode = AudioRolloffMode.Linear;
                audioSource.maxDistance = 20f;
            }
        }

        private Color HexToColor(string hex)
        {
            hex = hex.Replace("#", "");
            byte r = byte.Parse(hex.Substring(0, 2), System.Globalization.NumberStyles.HexNumber);
            byte g = byte.Parse(hex.Substring(2, 2), System.Globalization.NumberStyles.HexNumber);
            byte b = byte.Parse(hex.Substring(4, 2), System.Globalization.NumberStyles.HexNumber);
            return new Color32(r, g, b, 255);
        }

